const hoje = new Date();
const datas = [];
for (let i = 1; i <= 15; i++) {
  const d = new Date(hoje);
  d.setDate(d.getDate() - i);
  datas.push(d.toISOString().split('T')[0]);
}
return datas.map(data => ({ json: { data } }));

const item = $input.item.json;
const dataConsulta = ($('Últimos 15 dias').item && $('Últimos 15 dias').item.json && $('Últimos 15 dias').item.json.data) ? $('Últimos 15 dias').item.json.data : '';
const detalhes = item.detalhes || item.movimentos || item.data || [];
if (!Array.isArray(detalhes)) return [];
const out = [];
for (const d of detalhes) {
  const dataRaw = d.data_cashout || d.data || dataConsulta || '';
  const data = String(dataRaw).split('T')[0].trim();
  const valor = Math.abs(parseFloat(d.valor_cashout ?? d.valor ?? 0) || 0);
  if (!data || valor === 0) continue;
  const isPixCash = String(d.arranjo_pagamento || '').trim().toUpperCase() === 'PIX';
  const descricao = isPixCash ? 'PIX' : String(d.tipo_cashout || d.arranjo_pagamento || 'Cashout').trim();
  const pessoa = String(d.tipo_cashout || ('Cashout ' + (d.codigo_cashout || d.codigo_ur || ''))).trim() || 'Cashout';
  const id_unico = 'c-' + data + '-' + (d.codigo_cashout || d.codigo_ur || '') + '-' + valor;
  out.push({ json: { data, pessoa, valor, descricao, tipo: 'entrada', id_unico } });
}
return out;

