  const data = String(dataRaw).split('T')[0].trim();
  const pessoa = String(d.descricao || d.nome_comprador || d.nome || d.payerName || d.pessoa || ('Transação ' + (d.codigo_venda || d.codigo_transacao || ''))).trim() || 'Sem descrição';
  const valor = Math.abs(parseFloat(d.valor_total_transacao ?? d.valor_parcela ?? d.valor ?? d.amount ?? d.value ?? 0) || 0);
  const isPix = (d.meio_pagamento == 11 || String(d.meio_pagamento) === '11') || String(d.arranjo_ur || '').trim().toUpperCase() === 'PIX' || String(d.arranjo_pagamento || '').trim().toUpperCase() === 'PIX';
  const descricao = isPix ? 'PIX' : String(d.arranjo_ur || d.tipoMovimento || d.metodo || d.paymentMethod || d.tipo_transacao || 'Transação').trim();
  const tipo = (d.tipo || (parseFloat(d.valor_total_transacao ?? d.valor_parcela ?? d.valor ?? d.amount ?? d.value ?? 0) >= 0 ? 'entrada' : 'saida')).toString().toLowerCase();
  const tipoFinal = tipo === 'entrada' ? 'entrada' : 'saida';
  if (!data || valor === 0) continue;
  const id_unico = data + '-' + (d.codigo_transacao || d.codigo_venda || pessoa) + '-' + valor;
  out.push({ json: { data, pessoa, valor, descricao, tipo: tipoFinal, id_unico } });
}
return out;

