const itens = $input.all().map(i => i.json);
const existentes = new Set(($('Id_unicos no Supabase').all() || []).map(i => i.json.id_unico).filter(Boolean));
const novos = itens.filter(o => o.id_unico && !existentes.has(o.id_unico));
return novos.map(o => ({ json: o }));
